## Summary

- Problem: voice-call generated persisted session keys still used raw `voice:*` keys, so multi-agent voice routing could diverge from the gateway's canonical `agent:<agentId>:voice:*` session key shape.
- Solution: generate canonical voice session keys with the normalized voice agent id while preserving explicit session key overrides.
- What changed: updated the voice-call session key resolver and refreshed manager/runtime/response-generator tests that assert generated persisted keys.
- What did NOT change: explicit session key overrides still pass through unchanged.

Fixes #83967

## Real behavior proof

Behavior addressed: Generated voice-call manager paths now create and persist canonical `agent:<agentId>:voice:*` keys instead of bare `voice:*` keys, while explicit session key overrides remain unchanged.

Real environment tested: Local Linux checkout on Node with the voice-call manager event, outbound, and store modules loaded through `tsx`.

Exact steps or command run after this patch:
```bash
corepack pnpm@11.2.2 exec tsx - <<'TS'
import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { VoiceCallConfigSchema } from "./extensions/voice-call/src/config.ts";
import {
  clearVoiceCallStateRuntime,
  setVoiceCallStateRuntime,
} from "./extensions/voice-call/src/runtime-state.ts";
import { processEvent } from "./extensions/voice-call/src/manager/events.ts";
import { initiateCall } from "./extensions/voice-call/src/manager/outbound.ts";
import { loadActiveCallsFromStore } from "./extensions/voice-call/src/manager/store.ts";

function createMemorySyncKeyedStore() {
  const rows = new Map<string, { key: string; value: unknown; createdAt: number }>();
  return {
    register: (key: string, value: unknown) => {
      rows.set(key, { key, value, createdAt: Date.now() });
    },
    lookup: (key: string) => rows.get(key)?.value,
    delete: (key: string) => {
      rows.delete(key);
    },
    entries: () => [...rows.values()],
  };
}

const stores = new Map<string, ReturnType<typeof createMemorySyncKeyedStore>>();
setVoiceCallStateRuntime({
  state: {
    resolveStateDir: () => "",
    openKeyedStore: (() => {
      throw new Error("unused");
    }) as never,
    openSyncKeyedStore: (options: { namespace?: string }) => {
      const namespace = options.namespace ?? "default";
      let store = stores.get(namespace);
      if (!store) {
        store = createMemorySyncKeyedStore();
        stores.set(namespace, store);
      }
      return store as never;
    },
    openChannelIngressQueue: (() => {
      throw new Error("unused");
    }) as never,
  },
});

const storePath = fs.mkdtempSync(path.join(os.tmpdir(), "openclaw-voice-call-proof-"));
const config = VoiceCallConfigSchema.parse({
  enabled: true,
  provider: "twilio",
  fromNumber: "+15550000000",
  inboundPolicy: "open",
  agentId: "Voice",
});

const inboundCtx: any = {
  activeCalls: new Map(),
  providerCallIdMap: new Map(),
  processedEventIds: new Set(),
  rejectedProviderCallIds: new Set(),
  provider: null,
  config,
  storePath,
  webhookUrl: "https://example.invalid/voice",
  activeTurnCalls: new Set(),
  transcriptWaiters: new Map(),
  maxDurationTimers: new Map(),
  initialMessageInFlight: new Set(),
};
processEvent(inboundCtx, {
  id: "evt-proof-1",
  type: "call.initiated",
  callId: "provider-call-1",
  providerCallId: "provider-call-1",
  timestamp: Date.now(),
  direction: "inbound",
  from: "+1 (555) 000-1111",
  to: "+15550000000",
});

const inboundCall = [...inboundCtx.activeCalls.values()][0] as any;
let loaded = loadActiveCallsFromStore(storePath);
const persistedInbound = loaded.activeCalls.get(inboundCall.callId) as any;

const outboundCtx: any = {
  activeCalls: new Map(),
  providerCallIdMap: new Map(),
  processedEventIds: new Set(),
  rejectedProviderCallIds: new Set(),
  provider: {
    name: "twilio",
    initiateCall: async () => ({ providerCallId: "provider-call-2" }),
  },
  config,
  storePath,
  webhookUrl: "https://example.invalid/voice",
  activeTurnCalls: new Set(),
  transcriptWaiters: new Map(),
  maxDurationTimers: new Map(),
  initialMessageInFlight: new Set(),
};
const outboundResult = await initiateCall(outboundCtx, "+1 (555) 000-2222", "meet-room-1");
const outboundCall = outboundCtx.activeCalls.get(outboundResult.callId) as any;
loaded = loadActiveCallsFromStore(storePath);
const persistedOutbound = loaded.activeCalls.get(outboundResult.callId) as any;

console.log(JSON.stringify(
  {
    inboundRuntimePath: {
      activeCallSessionKey: inboundCall.sessionKey,
      persistedCallSessionKey: persistedInbound?.sessionKey,
      providerCallIdMappedToPersistedCall:
        loaded.providerCallIdMap.get("provider-call-1") === inboundCall.callId,
    },
    outboundExplicitOverridePath: {
      activeCallSessionKey: outboundCall?.sessionKey,
      persistedCallSessionKey: persistedOutbound?.sessionKey,
      providerCallId: outboundCall?.providerCallId,
      success: outboundResult.success,
    },
  },
  null,
  2,
));

for (const timer of inboundCtx.maxDurationTimers.values()) {
  clearTimeout(timer as NodeJS.Timeout);
}
for (const timer of outboundCtx.maxDurationTimers.values()) {
  clearTimeout(timer as NodeJS.Timeout);
}
clearVoiceCallStateRuntime();
fs.rmSync(storePath, { recursive: true, force: true });
TS
```

